$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_8942d7461e33e2685a59edc299ba85ac'] = 'Botz aktivéieren';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_93cba07454f06a4a960172bbd6e2a435'] = 'Jo';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_bafd7322c6e97d25b6299b5d6fe8920b'] = 'Nee';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_83112255bb4233cad4276eab160483e8'] = 'Schalt de Botzer un oder aus. Wann deaktivéiert, läschen d\'Cron-URL an de manuelle Laf-Knäppchen keng al Statistiken. Benotzt dëse Schalter, wann de Modul installéiert bleiwe soll, awer all Botzaktivitéit temporär gestoppt gëtt.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_896e1fd6ab19d8bbd2f58f989fbaac76'] = 'Erhale Deeg fir Verbindungsstatistiken';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_b878a67f82524d412dae79ad597ff402'] = 'Reien déi méi al si wéi dëse Wäert ginn aus connections, connections_source an connections_page geläscht.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_5ee406d769ac3887713d3308a0d01601'] = 'Gitt d\'Zuel vun Deeg an, fir déi réi PrestaShop-Besucherstatistike gespäichert solle ginn. Beispill: 60 bedeit datt de Modul déi lescht 60 Deeg behält an eeler Opzeechnungen aus ps_connections, ps_connections_source an ps_connections_page läscht. Setzt dëst net op 1, ausser Dir sidd sécher datt Dir keng rezent Besucherstatistike braucht.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_1300769d8d72fc8218b40772f1c25efc'] = 'Batchgréisst';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_631c4c75cb36e0fcee3da42ef67e730e'] = 'Maximal Unzuel u Verbindungen, déi an engem Batch veraarbecht ginn.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_acbc6e359c79ace4ef9b5398148c13e2'] = 'Gitt an, wéi vill Haapt-Verbindungsopzeechnungen an engem interne Batch veraarbecht kënne ginn. Méi kleng Wäerter si méi sécher op schwaachem Hosting, brauchen awer méi Cron-Leef. Méi grouss Wäerter botzen méi séier, kënnen awer Datebanksperren méi laang halen. Recommandéierte Startwäert: 1000 bis 5000; erhéijen nëmmen no Runtime-Test.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_2806977593fb4c23003cc11306b135d1'] = 'Maximum Batches pro Laf';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_d31a094a19379b58b63b51ef0f9d9362'] = 'Limitéiert wéi vill Aarbecht eng Cron-Ausféierung maache kann.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_e221a5a91ea62a43adc5bb15614eb578'] = 'Gitt an, wéi vill Batches wärend enger Cron-Ausféierung lafe kënnen. Déi méiglech total geläschte Haapt-Verbindungsopzeechnungen pro Laf sinn ongeféier Batchgréisst mol Maximum Batches pro Laf. Beispill: 5000 an 10 bedeit bis zu ongeféier 50000 Haaptopzeechnungen an engem Cron-Laf. Reduzéiert dëst, wann de Shop wärend der Botz méi lues gëtt.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_a1a47524ffa9c839887703df1fbe70a3'] = 'ps_layered_filter_block botzen';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_924684322fe68e56ef9205e7f480f598'] = 'Läscht de Cache vum faceted/layered Sichblock mat TRUNCATE TABLE. D\'Tabell gëtt vu MySQL/MariaDB eidel nei erstallt.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_92a6452eb793565a92aa28e5f9a3f2e5'] = 'Aktivéiert dëst nëmmen, wann ps_layered_filter_block ze grouss gëtt oder alen faceted search Cache enthält. Dëst läscht keng Produkter, Kategorien oder de layered Präisindex. Nom Botzen kann PrestaShop oder de faceted search Modul dëse Cache bei Bedarf nei opbauen.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_bf45506cce2494894a9df6ff4bdf83ae'] = 'Traffic-Quellstatistike virum Läschen aggregéieren';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_d7e1a0c7e7973ebcde37aa659525105d'] = 'Späichert deeglech zesummegefaasst Traffic-Quellstatistike virum Läsche vun de réie Reien.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ae729759e10d7a626a8622321932a1f4'] = 'Wann aktivéiert, späichert de Modul eng kleng deeglech Zesummefaassung ier réi PrestaShop-Statistiken ewechgeholl ginn. Et hält Zuelen wéi Visiten, Säitevisiounen, Quell-Domain an UTM-Wäerter. Et späichert keng IP-Adressen, voll Referrer-URLen oder User-Agent Strings. Deaktivéiert et, wann Dir nëmme läsche wëllt a keng historesch Quell-Zesummefaassunge braucht.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ce2b282d224153cccd645f28504ab4e2'] = 'Erhale Deeg fir aggregéiert Statistiken';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_c3b4d14f7bff29c221039e891918f2dd'] = 'Wéi laang déi kleng deeglech Zesummefaassungstabell erhale bleiwe soll.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_a97a6a6ab09f48206a543fdc7321bb60'] = 'Gitt an, wéi vill Deeg aggregéiert Traffic-Zesummefaassungen an der Modul-Tabell bleiwe sollen. Beispill: 730 hält ongeféier zwee Joer deeglech Quell-Zesummefaassungen. Dës Astellung beaflosst nëmmen d\'Tabell ps_jooim_dbcleaner_traffic_daily, net déi originell PrestaShop Statistik-Tabellen.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_4d4c70d739ad72835a8b62a81e07c611'] = 'Timeout fir al Sperr a Sekonnen';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ef4f59605eb7e54ec7df26e3755b7edf'] = 'Schutz géint zwee Botzprozesser déi gläichzäiteg lafen.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_2c1824ea38ec688698a26f01a46e6b16'] = 'Gitt d\'Zuel vu Sekonnen an, no där eng net ofgeschloss Botz-Sperr als verlooss gëllt. Dëst schützt d\'Datebank virun zwou gläichzäitege Cron-Ausféierungen. Recommandéierte Wäert: 7200. Nëmme reduzéieren, wann de Cron garantéiert séier fäerdeg ass.';
