$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_92a6452eb793565a92aa28e5f9a3f2e5'] = 'Aktivéiert dëst nëmmen, wann ps_layered_filter_block ze grouss gëtt oder alen faceted search Cache enthält. Dëst läscht keng Produkter, Kategorien oder de layered Präisindex. Nom Botzen kann PrestaShop oder de faceted search Modul dëse Cache bei Bedarf nei opbauen.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_bf45506cce2494894a9df6ff4bdf83ae'] = 'Traffic-Quellstatistike virum Läschen aggregéieren';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_d7e1a0c7e7973ebcde37aa659525105d'] = 'Späichert deeglech zesummegefaasst Traffic-Quellstatistike virum Läsche vun de réie Reien.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_ae729759e10d7a626a8622321932a1f4'] = 'Wann aktivéiert, späichert de Modul eng kleng deeglech Zesummefaassung ier réi PrestaShop-Statistiken ewechgeholl ginn. Et hält Zuelen wéi Visiten, Säitevisiounen, Quell-Domain an UTM-Wäerter. Et späichert keng IP-Adressen, voll Referrer-URLen oder User-Agent Strings. Deaktivéiert et, wann Dir nëmme läsche wëllt a keng historesch Quell-Zesummefaassunge braucht.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_ce2b282d224153cccd645f28504ab4e2'] = 'Erhale Deeg fir aggregéiert Statistiken';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_c3b4d14f7bff29c221039e891918f2dd'] = 'Wéi laang déi kleng deeglech Zesummefaassungstabell erhale bleiwe soll.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_a97a6a6ab09f48206a543fdc7321bb60'] = 'Gitt an, wéi vill Deeg aggregéiert Traffic-Zesummefaassungen an der Modul-Tabell bleiwe sollen. Beispill: 730 hält ongeféier zwee Joer deeglech Quell-Zesummefaassungen. Dës Astellung beaflosst nëmmen d\'Tabell ps_jooim_dbcleaner_traffic_daily, net déi originell PrestaShop Statistik-Tabellen.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_4d4c70d739ad72835a8b62a81e07c611'] = 'Timeout fir al Sperr a Sekonnen';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_ef4f59605eb7e54ec7df26e3755b7edf'] = 'Schutz géint zwee Botzprozesser déi gläichzäiteg lafen.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_2c1824ea38ec688698a26f01a46e6b16'] = 'Gitt d\'Zuel vu Sekonnen an, no där eng net ofgeschloss Botz-Sperr als verlooss gëllt. Dëst schützt d\'Datebank virun zwou gläichzäitege Cron-Ausféierungen. Recommandéierte Wäert: 7200. Nëmme reduzéieren, wann de Cron garantéiert séier fäerdeg ass.';
